/**
 * Unified market data router — simulation-first.
 *
 * Option chains are GENERATED by a Black-Scholes engine (syntheticChain.js)
 * anchored on a real spot price (Yahoo Finance, with a baseline fallback).
 * This removes the dependency on fragile NSE/Yahoo option-chain scraping:
 * the chain is always available — 24/7, weekends included — with realistic
 * premiums, a volatility smile, and live Greeks that move correctly with
 * spot / IV / time. It is labelled "simulated" downstream; never a live feed.
 *
 * The spot price itself is still fetched live from Yahoo when possible, so
 * premiums track the real index; if that fails we fall back to a baseline.
 *
 * Every consumer (chainCache, /api/feed, /api/paper-trade/price, /api/expiries)
 * goes through this module, so the simulation is fully transparent to them.
 */

import { YAHOO_UNDERLYING, fetchSpot as yahooSpot } from "./yahooApi";
import { SYMBOL_CONFIG, generateExpiries, buildChain, baselineSpot } from "./syntheticChain";
import { LOT_SIZES } from "../nse/constants";

// lotSize lookup for downstream consumers
export const UNDERLYING = Object.fromEntries(
  Object.keys(SYMBOL_CONFIG).map((k) => [k, { lotSize: LOT_SIZES[k] ?? 50 }])
);

export async function fetchExpiryList(symbol) {
  return generateExpiries(symbol);
}

// Real spot when Yahoo answers, baseline otherwise — never throws.
export async function fetchSpot(symbol) {
  try {
    if (YAHOO_UNDERLYING[symbol]) {
      const s = await yahooSpot(symbol);
      if (Number.isFinite(s) && s > 0) return s;
    }
  } catch {
    /* fall through to baseline */
  }
  return baselineSpot(symbol);
}

// The "raw" payload carries everything transformChain needs. fetchOptionChain
// is async (it anchors on a live spot); transformChain stays sync.
export async function fetchOptionChain(symbol, expiry) {
  const spot = await fetchSpot(symbol);
  return { symbol, expiry, spot };
}

export function transformChain(raw) {
  return buildChain(raw.symbol, raw.expiry, raw.spot);
}
